1	const BASE_PRICE_BY_TYPE: Record<string, number> = {
2	  potion: 40,
3	  amulet: 60,
4	  staff: 80,
5	  sword: 100,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	const RUNE_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
10	const RUNE_COMPONENT_BLOCK_SIZE = 3;
11	const RUNE_COMPONENT_BLOCK_PRICE = 60;
12	
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	
17	const LOYALTY_THRESHOLD_YEARS = 2;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const FOLLOWUP_THRESHOLD_PREVIOUS_QUOTES = 1;
20	const FOLLOWUP_DISCOUNT_RATE = 0.15;
21	
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	const DEDUCTIBLE_PER_ITEM = 100;
26	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
27	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
28	
29	export function claim(input: { policy: { items: { type: string; material?: string; enchantment?: number }[] }; incident: { cause?: string; damages: { itemType: string; amount: number }[] } }): number {
30	  const damages = input.incident.damages;
31	  const policyItems = input.policy.items;
32	  const totalPayout = damages.reduce((payoutSoFar, damage) => {
33	    const policyItem = policyItems.find((item) => item.type === damage.itemType);
34	    const hasHighEnchantment = (policyItem?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
35	    const reimbursable = hasHighEnchantment ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE : damage.amount;
36	    return payoutSoFar + (reimbursable - DEDUCTIBLE_PER_ITEM);
37	  }, 0);
38	  return Math.floor(totalPayout);
39	}
40	
41	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string; enchantment?: number; cursed?: boolean }[]; previousQuoteCount?: number }): number {
42	  const items = input.items;
43	  const countByType: Record<string, number> = {};
44	  for (const item of items) {
45	    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
46	  }
47	  let basePrice = 0;
48	  for (const type of Object.keys(countByType)) {
49	    const count = countByType[type];
50	    const formsRuneBlock = RUNE_COMPONENT_TYPES.has(type) && count === RUNE_COMPONENT_BLOCK_SIZE;
51	    if (formsRuneBlock) {
52	      basePrice += RUNE_COMPONENT_BLOCK_PRICE;
53	    } else {
54	      basePrice += count * BASE_PRICE_BY_TYPE[type];
55	    }
56	  }
57	  let highEnchantmentSurcharges = 0;
58	  let cursedSurcharges = 0;
59	  for (const item of items) {
60	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
61	      highEnchantmentSurcharges += BASE_PRICE_BY_TYPE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
62	    }
63	    if (item.cursed === true) {
64	      cursedSurcharges += BASE_PRICE_BY_TYPE[item.type] * CURSE_SURCHARGE_RATE;
65	    }
66	  }
67	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
68	  const qualifiesForLoyaltyDiscount = input.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
69	  const loyaltyDiscount = qualifiesForLoyaltyDiscount ? basePrice * LOYALTY_DISCOUNT_RATE : 0;
70	  const qualifiesForFollowUpDiscount = (input.previousQuoteCount ?? 0) >= FOLLOWUP_THRESHOLD_PREVIOUS_QUOTES;
71	  const followUpDiscount = qualifiesForFollowUpDiscount ? basePrice * FOLLOWUP_DISCOUNT_RATE : 0;
72	  const premium = basePrice + cursedSurcharges + highEnchantmentSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
73	  return Math.ceil(premium);
74	}
